  def withdraw(pid, amount) do
    GenServer.cast(pid, {:withdraw, amount})
  end

  @impl true
  def handle_cast({:deposit, amount}, balance) do
    new_balance = balance + amount
    :ets.insert(:bank_balances, {self(), new_balance})
    {:noreply, new_balance}
  end

  @impl true
  def handle_cast({:withdraw, amount}, balance) do
    case :ets.lookup(:bank_balances, self()) do
      [] ->
        IO.puts("Insufficient funds")
        {:noreply, balance}

      [{_pid, current_balance}] when current_balance >= amount ->
        new_balance = current_balance - amount
        :ets.insert(:bank_balances, {self(), new_balance})
        {:noreply, new_balance}
    end
  end

  @impl true
  def handle_call({:get_balance}, _from, balance) do
    {:reply, balance, balance}
